import{_ as e,o as t,c as i,a2 as r}from"./chunks/framework.BQ1gajhD.js";const b=JSON.parse('{"title":"北京旅游攻略微信小程序设计方案","description":"","frontmatter":{},"headers":[],"relativePath":"superpowers/specs/2026-07-23-beijing-travel-miniapp-design.md","filePath":"superpowers/specs/2026-07-23-beijing-travel-miniapp-design.md","lastUpdated":1784779212000}'),l={name:"superpowers/specs/2026-07-23-beijing-travel-miniapp-design.md"};function d(o,a,h,n,s,p){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="北京旅游攻略微信小程序设计方案" tabindex="-1">北京旅游攻略微信小程序设计方案 <a class="header-anchor" href="#北京旅游攻略微信小程序设计方案" aria-label="Permalink to &quot;北京旅游攻略微信小程序设计方案&quot;">​</a></h1><h2 id="_1-目标与边界" tabindex="-1">1. 目标与边界 <a class="header-anchor" href="#_1-目标与边界" aria-label="Permalink to &quot;1. 目标与边界&quot;">​</a></h2><p>将现有 VitePress 项目 <code>beijing-travel-guide</code> 的攻略内容逐步转化为一款供个人使用的原生微信小程序。小程序不依赖后端、不需要正式发布，所有攻略内容由项目内的 JSON 静态数据驱动。</p><p>第一版的目标是完成可用且视觉完整的框架，并迁移少量代表性页面来验证浏览、检索和收藏流程；其余内容在后续迭代中逐步补齐。</p><p>明确不做：账号体系、云数据库、服务端接口、支付、正式发布流程、在线地图和实时数据。</p><h2 id="_2-技术方案" tabindex="-1">2. 技术方案 <a class="header-anchor" href="#_2-技术方案" aria-label="Permalink to &quot;2. 技术方案&quot;">​</a></h2><ul><li>使用原生微信小程序 JavaScript、WXML、WXSS 和 JSON 配置文件。</li><li>不引入 UniApp、TypeScript、第三方组件库或构建步骤。</li><li>内容以本地 JSON 文件保存；页面通过统一的数据访问模块读取，不直接依赖数据文件的内部结构。</li><li>收藏和阅读记录使用微信本地存储，仅在当前设备和当前微信环境中保存。</li></ul><h2 id="_3-信息架构与-tabbar" tabindex="-1">3. 信息架构与 TabBar <a class="header-anchor" href="#_3-信息架构与-tabbar" aria-label="Permalink to &quot;3. 信息架构与 TabBar&quot;">​</a></h2><p>底部采用四个稳定入口：</p><table tabindex="0"><thead><tr><th>Tab</th><th>目的</th><th>首屏内容</th></tr></thead><tbody><tr><td>首页</td><td>快速开始与推荐</td><td>搜索入口、分类入口、趣玩推荐、精选内容、近期阅读</td></tr><tr><td>探索</td><td>浏览全部景点</td><td>五大分类、关键词搜索、筛选和景点列表</td></tr><tr><td>攻略</td><td>行前与行程信息</td><td>最佳时间、交通、门票、路线、美食、住宿、注意事项</td></tr><tr><td>我的</td><td>离线个人状态</td><td>收藏、阅读历史、数据说明和简单设置</td></tr></tbody></table><p>分类列表、搜索结果和景点详情均为非 Tab 页面，从首页或探索页进入。Tab 图标使用简洁线性风格：首页为屋檐、探索为罗盘、攻略为册页、我的为人物；选中态使用青绿色，未选中态使用浅灰蓝。</p><h2 id="_4-页面与功能" tabindex="-1">4. 页面与功能 <a class="header-anchor" href="#_4-页面与功能" aria-label="Permalink to &quot;4. 页面与功能&quot;">​</a></h2><h3 id="首页" tabindex="-1">首页 <a class="header-anchor" href="#首页" aria-label="Permalink to &quot;首页&quot;">​</a></h3><p>首页包含搜索入口、五大分类入口、趣玩模块、精选内容和近期阅读。趣玩模块使用横向滑动的小卡片，每张卡片展示封面、名称、分类和一句推荐文案。首批固定推荐内容为：</p><ol><li>天安门广场</li><li>中国国家博物馆</li><li>故宫博物院</li><li>曹雪芹故居</li></ol><p>趣玩内容由 JSON 中的推荐标记与排序控制，调整或新增推荐项无需修改页面代码。</p><h3 id="探索" tabindex="-1">探索 <a class="header-anchor" href="#探索" aria-label="Permalink to &quot;探索&quot;">​</a></h3><p>展示名胜古迹、近代历史、宗教建筑、博物馆和城市公园五大分类。用户可按分类浏览、使用本地关键词搜索，并进入景点详情。</p><h3 id="景点详情" tabindex="-1">景点详情 <a class="header-anchor" href="#景点详情" aria-label="Permalink to &quot;景点详情&quot;">​</a></h3><p>展示名称、分类、封面、摘要、标签、实用信息、分段正文和相关景点。正文由结构化内容区块渲染，避免在运行时解析 Markdown。</p><h3 id="攻略" tabindex="-1">攻略 <a class="header-anchor" href="#攻略" aria-label="Permalink to &quot;攻略&quot;">​</a></h3><p>展示最佳旅行时间、交通、门票预约、推荐路线、美食、住宿和注意事项等实用主题。</p><h3 id="我的" tabindex="-1">我的 <a class="header-anchor" href="#我的" aria-label="Permalink to &quot;我的&quot;">​</a></h3><p>展示本地收藏和阅读历史。数据仅保存在本地；若卸载小程序或清除微信缓存，记录会丢失。</p><h2 id="_5-数据设计与迁移" tabindex="-1">5. 数据设计与迁移 <a class="header-anchor" href="#_5-数据设计与迁移" aria-label="Permalink to &quot;5. 数据设计与迁移&quot;">​</a></h2><p>建立 <code>data/</code> 目录，按景点、分类、指南和路线拆分 JSON。景点的统一字段至少包括：<code>id</code>、名称、分类、封面、摘要、标签、开放/预约信息、正文区块、关联景点与推荐配置。</p><p>迁移分两步：</p><ol><li>首版先录入趣玩中的四个景点，并在各分类中补充少量代表景点，验证完整的浏览和搜索流程。</li><li>后续将现有 VitePress Markdown 按目录逐步整理为结构化 JSON，完成全量内容迁移。</li></ol><p>现有 SVG 资源优先复用。尚无真实封面的内容使用统一的渐变/插画占位样式；后续仅需替换 JSON 中的资源路径。</p><h2 id="_6-视觉方向" tabindex="-1">6. 视觉方向 <a class="header-anchor" href="#_6-视觉方向" aria-label="Permalink to &quot;6. 视觉方向&quot;">​</a></h2><p>采用清新、克制的“北京晨光”风格：暖米白作为页面底色，青绿色作为主色，朱砂红仅用于重点强调。页面保持充足留白，使用轻量圆角卡片、柔和阴影和层级明确的排版，避免厚重的仿古视觉。</p><h2 id="_7-异常状态与验证" tabindex="-1">7. 异常状态与验证 <a class="header-anchor" href="#_7-异常状态与验证" aria-label="Permalink to &quot;7. 异常状态与验证&quot;">​</a></h2><ul><li>JSON 缺少内容时显示友好的空状态。</li><li>图片加载失败时显示统一渐变占位。</li><li>搜索无结果时显示说明和清空筛选的操作入口。</li><li>本地存储失败不阻断阅读，仅提示收藏或历史记录未保存。</li></ul><p>每阶段均在微信开发者工具中导入、编译并验证：四个 Tab 的切换、页面跳转、JSON 渲染、本地搜索、收藏、阅读历史和异常空状态。</p><h2 id="_8-实施阶段" tabindex="-1">8. 实施阶段 <a class="header-anchor" href="#_8-实施阶段" aria-label="Permalink to &quot;8. 实施阶段&quot;">​</a></h2><ol><li>搭建原生 JavaScript 小程序骨架、四个 TabBar 页面与统一设计基础。</li><li>完成首页、趣玩模块和四个首批静态景点。</li><li>完成探索页、分类列表、详情页、本地搜索、收藏和阅读历史。</li><li>完成攻略页，并按现有 VitePress 目录逐步迁移剩余内容。</li></ol>',36)])])}const u=e(l,[["render",d]]);export{b as __pageData,u as default};
